  "storia": {
    "hero": {
      "eyebrow": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "La nostra storia" } },
      "title": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Cinquant'anni di fuoco acceso." } },
      "subtitle": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Dalla storica Cantina Cerea a Cascina Paradiso: una memoria di famiglia che continua a vivere a tavola." } }
    },
    "intro": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Nel cuore di Alzano Lombardo, una famiglia, una cascina, una tavola. Da oltre cinquant'anni raccontiamo la cucina bergamasca come l'abbiamo ricevuta: con rispetto, con memoria, con fuoco." } },
    "timeline": {
      "y1972": {
        "year": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "1972" } },
        "title": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Nasce Cantina Cerea" } },
        "body": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "La famiglia Cerea apre la sua cantina sulla via Ghilardi. Un luogo semplice, pensato per il vino, la polenta e i compagni di una sera." } }
      },
      "y1985": {
        "year": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "1985" } },
        "title": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "La brace diventa rito" } },
        "body": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Il camino a legna prende il centro della sala. Le carni del territorio, cotte sulla brace viva, diventano la nostra firma." } }
      },
      "y2005": {
        "year": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "2005" } },
        "title": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Cascina Cerea" } },
        "body": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "L'attività cresce. Il nome cambia insieme alla sala, ma lo spirito resta quello delle origini: cibo vero, persone vere." } }
      },
      "y2024": {
        "year": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Oggi" } },
        "title": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Bentornata, Roberta" } },
        "body": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Roberta riapre le porte della cascina e le restituisce il suo nome originario: Cascina Paradiso. Il cerchio si chiude, la storia ricomincia." } }
      }
    },
    "quote": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "Non abbiamo reinventato niente. Abbiamo solo ricordato." } },
    "quoteAuthor": { "t": 0, "b": { "t": 2, "i": [{ "t": 3 }], "s": "— Roberta" } }
  },
